INSERT INTO complaintEntity (id, order_id, product_id, product_name, user_name, category, rating, description, complaint_date) VALUES 
(1, 'ORD-10482', 'TSH-001', 'Classic Crew Neck Tee', 'Priya M.', 'sizing', 2, 'I ordered a Large based on your size chart but the shirt fits more like a Medium. Compared it to my other larges and yours is at least 2 inches narrower. Very misleading.', '2026-03-01 10:30:00'),
(2, 'ORD-10288', 'TSH-001', 'Classic Crew Neck Tee', 'Sam O.', 'quality', 2, 'The collar stretched out completely after one wear. It''s baggy and misshapen now. I''ve had many T-shirts and none have lost their shape this quickly.', '2026-03-01 10:30:00'),
(3, 'ORD-10301', 'TSH-001', 'Classic Crew Neck Tee', 'Mark T.', 'sizing', 2, 'Runs extremely small. I''m usually a Medium and had to return for an XL. The chest measurement on the size chart does not match the actual garment at all.', '2026-03-01 10:30:00'),
(4, 'ORD-10355', 'TSH-001', 'Classic Crew Neck Tee', 'Anita R.', 'quality', 1, 'The collar started rolling and curling after the second wash. It no longer lies flat and looks untidy. Expected better from a ''premium'' product.', '2026-03-01 10:30:00'),
(5, 'ORD-10410', 'TSH-001', 'Classic Crew Neck Tee', 'George W.', 'sizing', 3, 'The length is way too short for my torso. Even in XL it untucks constantly. Would be great if you offered a ''tall'' sizing option.', '2026-03-01 10:30:00'),
(6, 'ORD-10455', 'TSH-001', 'Classic Crew Neck Tee', 'Pooja S.', 'quality', 2, 'Visible pilling on the chest area after just three washes. The fabric is clearly low GSM and not suitable for regular use.', '2026-03-01 10:30:00'),
(7, 'ORD-10391', 'TSH-007', 'Graphic Print Oversized Tee', 'James K.', 'quality', 1, 'The print started cracking and peeling after just two washes. I followed the care instructions exactly. For the price I expected this to last longer than a month.', '2026-03-01 10:30:00'),
(8, 'ORD-10819', 'TSH-007', 'Graphic Print Oversized Tee', 'Rahul J.', 'quality', 1, 'The colour faded dramatically after the very first wash — went from a bright red to a washed-out pink. I washed it on cold as instructed. Clearly a dye quality issue.', '2026-03-01 10:30:00'),
(9, 'ORD-10521', 'TSH-007', 'Graphic Print Oversized Tee', 'Lucy F.', 'quality', 1, 'The graphic print is already peeling at the edges after one wash. The design looked great in the photos but the print quality is clearly very poor.', '2026-03-01 10:30:00'),
(10, 'ORD-10598', 'TSH-007', 'Graphic Print Oversized Tee', 'Daniel O.', 'quality', 2, 'Ink from the print transferred onto my white bed sheets after I wore it once. There was clearly no proper curing done during manufacturing.', '2026-03-01 10:30:00'),
(11, 'ORD-10612', 'TSH-007', 'Graphic Print Oversized Tee', 'Sneha B.', 'sizing', 2, 'The ''oversized'' fit is inconsistent — the body is loose but the sleeves are very tight. Feels like the sleeves belong to a different size entirely.', '2026-03-01 10:30:00'),
(12, 'ORD-10637', 'TSH-007', 'Graphic Print Oversized Tee', 'Aaron L.', 'quality', 1, 'After two washes the print has faded to nearly half its original brightness. The colors on the website look nothing like what you get after minimal use. False advertising.', '2026-03-01 10:30:00'),
(13, 'ORD-10557', 'TSH-003', 'Essential V-Neck Tee', 'Aisha N.', 'shipping', 2, 'My order was marked as delivered but nothing showed up at my door. Checked with my neighbours and the front desk — no package. It''s been 5 days and still no resolution.', '2026-03-01 10:30:00'),
(14, 'ORD-10334', 'TSH-003', 'Essential V-Neck Tee', 'Kevin G.', 'sizing', 2, 'Your size chart says a Large chest is 40-42 inches, but this shirt barely fits my 40-inch chest. The armholes are also very tight. Please update the chart or adjust the cut.', '2026-03-01 10:30:00'),
(15, 'ORD-10348', 'TSH-003', 'Essential V-Neck Tee', 'Tina M.', 'quality', 2, 'The V-neck is cut way too deep — nearly down to the chest. Not appropriate for a professional setting which is what I intended it for. The website photos are very deceiving.', '2026-03-01 10:30:00'),
(16, 'ORD-10366', 'TSH-003', 'Essential V-Neck Tee', 'Ravi P.', 'quality', 2, 'The fabric is extremely see-through. I can''t wear this without a layer underneath. The product description says nothing about it being sheer.', '2026-03-01 10:30:00'),
(17, 'ORD-10389', 'TSH-003', 'Essential V-Neck Tee', 'Hannah C.', 'sizing', 3, 'The women''s Small has very narrow shoulders — feels like it was cut for a child. The body length is fine but the shoulder seams sit halfway down my arm.', '2026-03-01 10:30:00'),
(18, 'ORD-10204', 'TSH-012', 'Vintage Washed Tee', 'Rohan S.', 'wrong_item', 1, 'I ordered a white graphic tee in size XL but received a black plain shirt in size M. Completely different item. I need this for an event next week — please sort this urgently.', '2026-03-01 10:30:00'),
(19, 'ORD-10218', 'TSH-012', 'Vintage Washed Tee', 'Paula D.', 'quality', 2, 'The ''vintage washed'' effect is very uneven — one side of the shirt is noticeably darker than the other. Looks like a manufacturing defect, not an intentional design.', '2026-03-01 10:30:00'),
(20, 'ORD-10244', 'TSH-012', 'Vintage Washed Tee', 'Nikhil A.', 'quality', 1, 'The shirt has small holes along one of the seams — looks like stress from the washing process used to create the vintage effect. Not wearable as-is.', '2026-03-01 10:30:00'),
(21, 'ORD-10261', 'TSH-012', 'Vintage Washed Tee', 'Grace H.', 'quality', 2, 'The colour looks great in photos but in person it just looks faded and old — not in a cool vintage way, just cheap. Very different from what was shown.', '2026-03-01 10:30:00'),
(22, 'ORD-10279', 'TSH-012', 'Vintage Washed Tee', 'Omar K.', 'sizing', 2, 'The shirt shrank significantly after the first wash even on a cold cycle. Went from a comfortable Large to something that fits like a Small. Very disappointing.', '2026-03-01 10:30:00'),
(23, 'ORD-10678', 'TSH-005', 'Heavyweight Cotton Tee', 'Linda H.', 'quality', 2, 'The fabric feels really rough and scratchy — nothing like the ''soft cotton'' description on the website. My skin was irritated after wearing it for a couple of hours.', '2026-03-01 10:30:00'),
(24, 'ORD-10691', 'TSH-005', 'Heavyweight Cotton Tee', 'James P.', 'quality', 2, 'Despite being marketed as heavyweight, this shirt feels thin and flimsy. The GSM must be much lower than advertised. I expected something more structured.', '2026-03-01 10:30:00'),
(25, 'ORD-10705', 'TSH-005', 'Heavyweight Cotton Tee', 'Meena V.', 'quality', 1, 'There are visible weaving imperfections in the fabric — random thick and thin patches across the chest. It''s clearly a quality control miss.', '2026-03-01 10:30:00'),
(26, 'ORD-10718', 'TSH-005', 'Heavyweight Cotton Tee', 'Chris B.', 'quality', 2, 'The fabric softness is inconsistent — the front feels different from the back and the sleeves. Seems like fabric from different batches was used to construct one shirt.', '2026-03-01 10:30:00'),
(27, 'ORD-10731', 'TSH-005', 'Heavyweight Cotton Tee', 'Zara I.', 'sizing', 3, 'The sizing is very boxy and unflattering. There''s no mention that this has a boxy fit on the product page — would be great to add fit type as a filter or label.', '2026-03-01 10:30:00'),
(28, 'ORD-10862', 'TSH-006', 'Slim Fit Pocket Tee', 'Fatima A.', 'quality', 1, 'The stitching on the left sleeve started unravelling after the first wash. There''s a loose thread about 4 inches long and the seam is coming apart. Terrible quality control.', '2026-03-01 10:30:00'),
(29, 'ORD-10622', 'TSH-006', 'Slim Fit Pocket Tee', 'Ben A.', 'shipping', 2, 'The tracking hasn''t updated in 9 days. It''s stuck on ''In Transit - Sorting Facility''. I need to know if my order is lost so I can request a replacement or refund.', '2026-03-01 10:30:00'),
(30, 'ORD-10877', 'TSH-006', 'Slim Fit Pocket Tee', 'Preet K.', 'quality', 1, 'The pocket is sewn on at a visible angle — it''s noticeably crooked. A basic quality check would have caught this. Not what I expect from a paid product.', '2026-03-01 10:30:00'),
(31, 'ORD-10891', 'TSH-006', 'Slim Fit Pocket Tee', 'Ellie T.', 'sizing', 2, 'The slim fit is so tight that the shirt pulls across the chest when I raise my arms. It also shows every bump which I wasn''t expecting from a plain tee.', '2026-03-01 10:30:00'),
(32, 'ORD-10905', 'TSH-006', 'Slim Fit Pocket Tee', 'Vikram N.', 'quality', 2, 'The pocket stitching came loose after a few days of wear — not even a wash. The pocket now sags off the shirt. This is a construction defect.', '2026-03-01 10:30:00'),
(33, 'ORD-10919', 'TSH-006', 'Slim Fit Pocket Tee', 'Sophie W.', 'quality', 1, 'There was a small tear near the armhole seam straight out of the packaging. I hadn''t even worn it yet. Clearly a defective unit that should not have passed inspection.', '2026-03-01 10:30:00'),
(34, 'ORD-10129', 'TSH-014', 'Relaxed Fit Drop Shoulder Tee', 'Tom B.', 'sizing', 3, 'The XS was way too large for me — runs at least one size bigger than standard. Would be helpful if you added measurements in cm to each size option.', '2026-03-01 10:30:00'),
(35, 'ORD-10143', 'TSH-014', 'Relaxed Fit Drop Shoulder Tee', 'Ria S.', 'sizing', 2, 'The drop shoulder seam sits almost at my elbow — it''s far too exaggerated. Not what I''d call a ''relaxed'' fit; it looks more like a costume. Size guide gave no indication of this.', '2026-03-01 10:30:00'),
(36, 'ORD-10157', 'TSH-014', 'Relaxed Fit Drop Shoulder Tee', 'Nathan G.', 'quality', 2, 'The fabric is so lightweight it''s practically transparent. For a relaxed oversized style I''d expect a more substantial material. This feels like sleepwear fabric.', '2026-03-01 10:30:00'),
(37, 'ORD-10171', 'TSH-014', 'Relaxed Fit Drop Shoulder Tee', 'Layla M.', 'sizing', 2, 'The body of the shirt is too wide but the sleeves are too short. The proportions feel off — like the pattern pieces don''t belong to the same design.', '2026-03-01 10:30:00'),
(38, 'ORD-10185', 'TSH-014', 'Relaxed Fit Drop Shoulder Tee', 'Harish D.', 'quality', 1, 'The hem is uneven — the back of the shirt is almost 3cm longer than the front on one side. This is a basic construction error.', '2026-03-01 10:30:00'),
(39, 'ORD-10530', 'TSH-011', 'Tie-Dye Festival Tee', 'David L.', 'website', 2, 'The product photos show a rich navy blue but what I received is closer to a dull grey. The colour difference is significant — I wouldn''t have ordered it if the photos were accurate.', '2026-03-01 10:30:00'),
(40, 'ORD-10544', 'TSH-011', 'Tie-Dye Festival Tee', 'Chloe R.', 'quality', 1, 'The dye bled massively in the first wash — ruined two other garments in the same load. There was no warning on the label to wash separately.', '2026-03-01 10:30:00'),
(41, 'ORD-10558', 'TSH-011', 'Tie-Dye Festival Tee', 'Amit P.', 'quality', 1, 'The dye smell is overpowering — even after two washes the chemical smell hasn''t faded. I can''t wear this until it goes away, if it ever does.', '2026-03-01 10:30:00'),
(42, 'ORD-10572', 'TSH-011', 'Tie-Dye Festival Tee', 'Sara J.', 'website', 2, 'Each tie-dye shirt is described as ''unique'' but mine looks nothing like any of the 6 photos shown. I understand variation, but the colour palette is completely different.', '2026-03-01 10:30:00'),
(43, 'ORD-10586', 'TSH-011', 'Tie-Dye Festival Tee', 'Leo C.', 'quality', 2, 'After one gentle wash the tie-dye pattern has faded to about 50% of its original vibrancy. The colors looked great on arrival but clearly the dye was not set properly.', '2026-03-01 10:30:00'),
(44, 'ORD-10447', 'TSH-008', 'City Skyline Graphic Tee', 'Sophie R.', 'wrong_item', 1, 'I ordered the ''City Skyline'' design but received a completely different graphic. The packing slip even shows the correct item — so something went wrong in fulfilment.', '2026-03-01 10:30:00'),
(45, 'ORD-10461', 'TSH-008', 'City Skyline Graphic Tee', 'Kabir H.', 'quality', 2, 'The skyline print is misaligned — the entire graphic is shifted 4cm to the left. It''s clearly not centred. A basic visual check should catch this before shipping.', '2026-03-01 10:30:00'),
(46, 'ORD-10475', 'TSH-008', 'City Skyline Graphic Tee', 'Maya W.', 'quality', 1, 'The print has tiny air bubbles trapped under it — you can feel them when you touch the graphic. After one wash several of these have already popped and left pits in the print.', '2026-03-01 10:30:00'),
(47, 'ORD-10489', 'TSH-008', 'City Skyline Graphic Tee', 'Josh F.', 'quality', 2, 'The graphic is printed so close to the collar that part of the design is hidden under the neckline fold. Poor placement planning for this design.', '2026-03-01 10:30:00'),
(48, 'ORD-10503', 'TSH-008', 'City Skyline Graphic Tee', 'Nadia B.', 'website', 3, 'The product listing shows this on a white shirt but it came on cream/off-white. Not a huge issue but the colour should be accurately described — ''white'' and ''cream'' are different.', '2026-03-01 10:30:00'),
(49, 'ORD-10315', 'TSH-009', 'Long Line Curved Hem Tee', 'Carlos D.', 'payment', 1, 'I was charged twice for the same order. I can see two identical transactions on my bank statement. Please refund the duplicate charge immediately.', '2026-03-01 10:30:00'),
(50, 'ORD-10490', 'TSH-009', 'Long Line Curved Hem Tee', 'Divya K.', 'website', 3, 'The product page shows ''In Stock'' but after placing my order and paying, I got an email saying the item is out of stock. The site inventory clearly isn''t updating in real time.', '2026-03-01 10:30:00'),
(51, 'ORD-10329', 'TSH-009', 'Long Line Curved Hem Tee', 'Felix A.', 'sizing', 2, 'The curved hem is so dramatically curved it looks strange when worn untucked — the sides are almost 8cm shorter than the back. This extreme cut wasn''t visible in product photos.', '2026-03-01 10:30:00'),
(52, 'ORD-10343', 'TSH-009', 'Long Line Curved Hem Tee', 'Isla M.', 'quality', 2, 'The hem stitching is already unravelling on the curved section. These areas need reinforced stitching because of the curved tension — clearly the manufacturer didn''t account for this.', '2026-03-01 10:30:00'),
(53, 'ORD-10357', 'TSH-009', 'Long Line Curved Hem Tee', 'Tyrone B.', 'sizing', 2, 'Listed as ''long line'' but on my 6''1" frame it''s a normal length. The description is misleading for taller customers. Please add the actual length in cm on the product page.', '2026-03-01 10:30:00'),
(54, 'ORD-10991', 'TSH-004', 'Organic Cotton Basic Tee', 'Arjun T.', 'payment', 2, 'I applied a 20% discount code at checkout but was charged full price. The code showed as valid and the total updated, so I''m not sure where it dropped off.', '2026-03-01 10:30:00'),
(55, 'ORD-10005', 'TSH-004', 'Organic Cotton Basic Tee', 'Claire B.', 'quality', 3, 'For an ''organic'' product I expected better. The fabric feels no different from a regular cheap tee. No certification details or organic standard is mentioned anywhere on the label or website.', '2026-03-01 10:30:00'),
(56, 'ORD-10019', 'TSH-004', 'Organic Cotton Basic Tee', 'Siddharth R.', 'website', 2, 'There is no information about which organic certification this product holds — GOTS, OCS, or otherwise. For customers who care about sustainability this is important and should be listed.', '2026-03-01 10:30:00'),
(57, 'ORD-10033', 'TSH-004', 'Organic Cotton Basic Tee', 'Freya L.', 'quality', 2, 'The shirt has a faint chemical smell straight from the packaging — unexpected for an ''organic'' product. I had to wash it twice before it was wearable.', '2026-03-01 10:30:00'),
(58, 'ORD-10047', 'TSH-004', 'Organic Cotton Basic Tee', 'Rajan M.', 'quality', 1, 'Shrank by nearly a full size in the first wash at 30 degrees. For a premium-priced organic tee this is unacceptable. It should be pre-shrunk before sale.', '2026-03-01 10:30:00'),
(59, 'ORD-10663', 'TSH-010', 'Striped Nautical Tee', 'Nina V.', 'shipping', 2, 'My package arrived completely squashed — the shirt had a big crease pressed into it and the cardboard insert was bent in half. Poor packaging for what''s supposed to be a gift.', '2026-03-01 10:30:00'),
(60, 'ORD-10677', 'TSH-010', 'Striped Nautical Tee', 'Aditya S.', 'quality', 2, 'The stripes are visibly uneven — some bands are wider than others and the alignment doesn''t match up at the side seams. Looks like a pattern-matching error in production.', '2026-03-01 10:30:00'),
(61, 'ORD-10690', 'TSH-010', 'Striped Nautical Tee', 'Beth C.', 'quality', 1, 'The white stripes have turned slightly yellow after just two washes. I followed the care label. The dye from the coloured stripes appears to be bleeding into the white sections.', '2026-03-01 10:30:00'),
(62, 'ORD-10703', 'TSH-010', 'Striped Nautical Tee', 'Liam O.', 'sizing', 2, 'The neck opening is very wide and keeps slipping off one shoulder. It doesn''t stay in place during normal movement. Seems like the neckband tension is wrong for this style.', '2026-03-01 10:30:00'),
(63, 'ORD-10716', 'TSH-010', 'Striped Nautical Tee', 'Neha G.', 'quality', 2, 'The stripes are misaligned at the collar — one side has a blue stripe at the top and the other has white. Makes the shirt look asymmetric and unprofessional.', '2026-03-01 10:30:00'),
(64, 'ORD-10755', 'TSH-013', 'Moisture Wicking Active Tee', 'Elena M.', 'website', 3, 'Your returns portal is broken — every time I try to submit my return reason, the page refreshes and loses my input. I''ve tried Chrome and Safari, both have the same issue.', '2026-03-01 10:30:00'),
(65, 'ORD-10769', 'TSH-013', 'Moisture Wicking Active Tee', 'Suresh P.', 'quality', 2, 'After a 30-minute workout the shirt was completely soaked — no different from a regular cotton tee. The moisture-wicking claim seems exaggerated or outright false.', '2026-03-01 10:30:00'),
(66, 'ORD-10783', 'TSH-013', 'Moisture Wicking Active Tee', 'Jenny H.', 'quality', 1, 'The anti-odour treatment wore off after just 4-5 washes. The shirt now smells terrible after any workout. The treatment should last much longer on a performance product.', '2026-03-01 10:30:00'),
(67, 'ORD-10797', 'TSH-013', 'Moisture Wicking Active Tee', 'Dev A.', 'quality', 2, 'The flatlock seams are rough and caused chafing on my shoulders during a long run. For an active-wear product the seam finishing must be smooth — this is a basic requirement.', '2026-03-01 10:30:00'),
(68, 'ORD-10811', 'TSH-013', 'Moisture Wicking Active Tee', 'Kate M.', 'sizing', 2, 'The women''s cut is very boxy — no waist shaping at all. It rides up during exercise which makes it unusable for working out. The fit design clearly wasn''t tested with movement.', '2026-03-01 10:30:00'),
(69, 'ORD-10174', 'TSH-015', 'Oversized Acid Wash Tee', 'Claire W.', 'wrong_item', 1, 'I received only one shirt but my order was for a pack of three. The invoice in the box shows all three items but only one was actually packed. Please ship the missing two.', '2026-03-01 10:30:00'),
(70, 'ORD-10188', 'TSH-015', 'Oversized Acid Wash Tee', 'Yusuf A.', 'quality', 1, 'The acid wash has left the fabric extremely thin in patches — almost worn through in places. This is a structural weakness that will turn into holes very quickly.', '2026-03-01 10:30:00'),
(71, 'ORD-10202', 'TSH-015', 'Oversized Acid Wash Tee', 'Tara N.', 'quality', 1, 'Strong chemical smell that hasn''t washed out after three cycles. My skin broke out in a rash after wearing it briefly. This needs to be investigated as a potential safety issue.', '2026-03-01 10:30:00'),
(72, 'ORD-10216', 'TSH-015', 'Oversized Acid Wash Tee', 'Ross F.', 'quality', 2, 'The oversized fit collapses and loses structure after one wash. The fabric doesn''t hold its shape and ends up looking completely shapeless rather than intentionally oversized.', '2026-03-01 10:30:00'),
(73, 'ORD-10230', 'TSH-015', 'Oversized Acid Wash Tee', 'Priya T.', 'website', 2, 'No care instructions are shown on the product page and the label inside the shirt is illegible — the print has faded entirely. I have no idea how to safely wash this item.', '2026-03-01 10:30:00'),
(74, 'ORD-10743', 'TSH-002', 'Bamboo Blend Soft Tee', 'Meera P.', 'shipping', 2, 'I paid for express 2-day delivery but my order arrived after 8 days. The extra shipping fee should definitely be refunded given the delay.', '2026-03-01 10:30:00'),
(75, 'ORD-10757', 'TSH-002', 'Bamboo Blend Soft Tee', 'Ian D.', 'quality', 2, 'The bamboo fabric has pilled heavily around the underarms after minimal wear. For a premium-priced eco fabric this level of pilling so quickly is unacceptable.', '2026-03-01 10:30:00'),
(76, 'ORD-10771', 'TSH-002', 'Bamboo Blend Soft Tee', 'Mansi R.', 'quality', 2, 'The shirt has stretched noticeably around the neckline and hem after just a few wears — no washing yet. Bamboo fabric needs better structure to hold its shape during wear.', '2026-03-01 10:30:00'),
(77, 'ORD-10785', 'TSH-002', 'Bamboo Blend Soft Tee', 'Alex T.', 'quality', 3, 'The colour options online look much more vibrant than what arrived. The sage green I ordered looks like a washed-out grey in person. Accurate colour photography would help a lot.', '2026-03-01 10:30:00'),
(78, 'ORD-10799', 'TSH-002', 'Bamboo Blend Soft Tee', 'Noor H.', 'sizing', 2, 'The bamboo fabric clings to the body much more than expected — not in a flattering way. The product should mention that this fabric has a body-hugging drape so customers can size up.', '2026-03-01 10:30:00');
